// Generated by GitHub Copilot
import { countDomainRecords } from './repository.js';
import { verifyDatabaseConnection } from './db.js';

const INCIDENT_SEVERITIES = ['low', 'medium', 'high', 'critical'];

/**
 * Resolves worker mode from CLI args.
 */
function resolveMode() {
    const mode = process.argv[2]?.trim().toLowerCase();
    if (mode === 'publisher' || mode === 'scheduler') {
        return mode;
    }
    return 'worker';
}

/**
 * Emits periodic heartbeats and lightweight domain stats.
 */
async function runWorkerMode() {
    console.log('[worker] base worker started');

    setInterval(async () => {
        try {
            const incidentCount = await countDomainRecords('incidents');
            const riskCount = await countDomainRecords('risks');
            console.log(`[worker] heartbeat incidents=${incidentCount} risks=${riskCount}`);
        } catch (error) {
            console.error('[worker] heartbeat failed', error);
        }
    }, 30_000);
}

/**
 * Publishes queue-like telemetry by polling API stats endpoint.
 */
async function runPublisherMode() {
    const apiBase = process.env.API_BASE_URL ?? 'http://api:5000/api';
    console.log(`[publisher] publisher started against ${apiBase}`);

    setInterval(async () => {
        try {
            const response = await fetch(`${apiBase}/admin/stats`, {
                method: 'GET',
                headers: {
                    Accept: 'application/json',
                },
            });

            if (!response.ok) {
                throw new Error(`Stats endpoint returned ${response.status}`);
            }

            const data = await response.json();
            console.log(`[publisher] stats snapshot at ${new Date().toISOString()} domains=${Object.keys(data?.counts ?? {}).length}`);
        } catch (error) {
            console.error('[publisher] failed to poll stats endpoint', error);
        }
    }, 20_000);
}

/**
 * Schedules synthetic incidents via API to mimic background task creation.
 */
async function runSchedulerMode() {
    const apiBase = process.env.API_BASE_URL ?? 'http://api:5000/api';
    console.log(`[scheduler] scheduler started against ${apiBase}`);

    setInterval(async () => {
        try {
            const timestamp = new Date();
            const severity = INCIDENT_SEVERITIES[timestamp.getUTCMinutes() % INCIDENT_SEVERITIES.length];

            const payload = {
                title: `Synthetic scheduled incident ${timestamp.toISOString()}`,
                description: 'Generated by scheduler service for local real-time testing.',
                severity,
                status: 'open',
                category: 'automation',
                affectedSystems: ['scheduler'],
                reporter: 'worker-scheduler',
                assignee: 'SOC Team',
                reportedAt: timestamp.toISOString(),
            };

            const response = await fetch(`${apiBase}/incidents`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    Accept: 'application/json',
                },
                body: JSON.stringify(payload),
            });

            if (!response.ok) {
                throw new Error(`Incident create returned ${response.status}`);
            }

            const created = await response.json();
            console.log(`[scheduler] created incident ${created.id}`);
        } catch (error) {
            console.error('[scheduler] failed to create scheduled incident', error);
        }
    }, 45_000);
}

/**
 * Main worker entrypoint selecting mode-specific behavior.
 */
async function main() {
    const mode = resolveMode();

    await verifyDatabaseConnection();
    console.log(`[${mode}] database connectivity verified`);

    if (mode === 'publisher') {
        await runPublisherMode();
        return;
    }

    if (mode === 'scheduler') {
        await runSchedulerMode();
        return;
    }

    await runWorkerMode();
}

main().catch((error) => {
    console.error('[worker] startup failed', error);
    process.exit(1);
});
